1	import type { AnalyticsInterval, MarketAnalyticsSeries } from "@/lib/api/types";
2	import { formatProbability } from "@/lib/utils/format";
3	import {
4	  buildLinePath,
5	  formatTimestampLabel,
6	  getOutcomeColor,
7	  scaleNumber,
8	} from "./chartUtils";
9	
10	interface PriceChartProps {
11	  series: MarketAnalyticsSeries[];
12	  interval: AnalyticsInterval;
13	}
14	
15	const WIDTH = 760;
16	const HEIGHT = 320;
17	const MARGIN = { top: 24, right: 24, bottom: 48, left: 52 };
18	
19	export function PriceChart({ series, interval }: PriceChartProps) {
20	  const timestamps = series
21	    .flatMap((outcome) => outcome.points.map((point) => Date.parse(point.emittedAt)))
22	    .filter((value) => Number.isFinite(value));
23	  const domainStart = timestamps.length > 0 ? Math.min(...timestamps) : Date.now();
24	  const domainEnd = timestamps.length > 1 ? Math.max(...timestamps) : domainStart + 1;
25	  const chartLeft = MARGIN.left;
26	  const chartRight = WIDTH - MARGIN.right;
27	  const chartTop = MARGIN.top;
28	  const chartBottom = HEIGHT - MARGIN.bottom;
29	  const xTickCount = timestamps.length > 1 ? Math.min(4, timestamps.length) : 1;
30	  const xTicks = Array.from({ length: xTickCount }, (_, index) => {
31	    if (xTickCount === 1) {
32	      return domainStart;
33	    }
34	
35	    return domainStart + ((domainEnd - domainStart) * index) / (xTickCount - 1);
36	  });
37	
38	  return (
39	    <section style={cardStyle}>
40	      <div style={headerStyle}>
41	        <div>
42	          <h2 style={titleStyle}>Probability History</h2>
43	          <p style={subtitleStyle}>
44	            Accepted unconditional prices only. Event trades and contextual edits
45	            stay out of the line series.
46	          </p>
47	        </div>
48	        <div style={legendStyle}>
49	          {series.map((outcome, index) => (
50	            <span key={outcome.outcomeId} style={legendItemStyle}>
51	              <span
52	                style={{
53	                  ...legendDotStyle,
54	                  background: getOutcomeColor(index),
55	                }}
56	              />
57	              {outcome.outcomeName}
58	            </span>
59	          ))}
60	        </div>
61	      </div>
62	
63	      <div style={{ overflowX: "auto" }}>
64	        <svg
65	          data-testid="price-chart"
66	          role="img"
67	          aria-label="Probability history chart"
68	          viewBox={`0 0 ${WIDTH} ${HEIGHT}`}
69	          style={{ width: "100%", height: "auto", minWidth: 460 }}
70	        >
71	          {[1, 0.75, 0.5, 0.25, 0].map((value) => {
72	            const y = scaleNumber(value, 0, 1, chartBottom, chartTop);
73	            return (
74	              <g key={value}>
75	                <line
76	                  x1={chartLeft}
77	                  y1={y}
78	                  x2={chartRight}
79	                  y2={y}
80	                  stroke="rgba(139, 143, 163, 0.28)"
81	                  strokeDasharray="4 4"
82	                />
83	                <text
84	                  x={chartLeft - 10}
85	                  y={y + 4}
86	                  fill="var(--color-text-muted)"
87	                  fontSize="11"
88	                  textAnchor="end"
89	                >
90	                  {formatProbability(value)}
91	                </text>
92	              </g>
93	            );
94	          })}
95	
96	          {xTicks.map((tick) => {
97	            const x = scaleNumber(tick, domainStart, domainEnd, chartLeft, chartRight);
98	            return (
99	              <g key={tick}>
100	                <line
101	                  x1={x}
102	                  y1={chartTop}
103	                  x2={x}
104	                  y2={chartBottom}
105	                  stroke="rgba(139, 143, 163, 0.16)"
106	                />
107	                <text
108	                  x={x}
109	                  y={HEIGHT - 14}
110	                  fill="var(--color-text-muted)"
111	                  fontSize="11"
112	                  textAnchor="middle"
113	                >
114	                  {formatTimestampLabel(new Date(tick).toISOString(), interval)}
115	                </text>
116	              </g>
117	            );
118	          })}
119	
120	          <line
121	            x1={chartLeft}
122	            y1={chartBottom}
123	            x2={chartRight}
124	            y2={chartBottom}
125	            stroke="var(--color-border)"
126	          />
127	          <line
128	            x1={chartLeft}
129	            y1={chartTop}
130	            x2={chartLeft}
131	            y2={chartBottom}
132	            stroke="var(--color-border)"
133	          />
134	
135	          {series.map((outcome, outcomeIndex) => {
136	            const points = outcome.points.map((point) => ({
137	              x: scaleNumber(
138	                Date.parse(point.emittedAt),
139	                domainStart,
140	                domainEnd,
141	                chartLeft,
142	                chartRight,
143	              ),
144	              y: scaleNumber(point.probability, 0, 1, chartBottom, chartTop),
145	            }));
146	            const color = getOutcomeColor(outcomeIndex);
147	
148	            return (
149	              <g key={outcome.outcomeId}>
150	                {points.length > 1 && (
151	                  <path
152	                    d={buildLinePath(points)}
153	                    fill="none"
154	                    stroke={color}
155	                    strokeWidth="3"
156	                    strokeLinejoin="round"
157	                    strokeLinecap="round"
158	                  />
159	                )}
160	                {points.map((point, pointIndex) => (
161	                  <circle
162	                    key={`${outcome.outcomeId}-${pointIndex}`}
163	                    cx={point.x}
164	                    cy={point.y}
165	                    r="4"
166	                    fill={color}
167	                    stroke="var(--color-bg-surface)"
168	                    strokeWidth="2"
169	                  />
170	                ))}
171	              </g>
172	            );
173	          })}
174	        </svg>
175	      </div>
176	    </section>
177	  );
178	}
179	
180	const cardStyle: React.CSSProperties = {
181	  padding: "var(--space-lg)",
182	  borderRadius: "var(--radius-lg)",
183	  border: "1px solid var(--color-border)",
184	  background: "var(--color-bg-surface)",
185	};
186	
187	const headerStyle: React.CSSProperties = {
188	  display: "flex",
189	  justifyContent: "space-between",
190	  gap: "var(--space-md)",
191	  flexWrap: "wrap",
192	  marginBottom: "var(--space-md)",
193	};
194	
195	const titleStyle: React.CSSProperties = {
196	  fontSize: "1.05rem",
197	  fontWeight: 600,
198	};
199	
200	const subtitleStyle: React.CSSProperties = {
201	  marginTop: "var(--space-xs)",
202	  fontSize: "0.8rem",
203	  color: "var(--color-text-muted)",
204	  maxWidth: 560,
205	};
206	
207	const legendStyle: React.CSSProperties = {
208	  display: "flex",
209	  gap: "var(--space-sm)",
210	  alignItems: "center",
211	  flexWrap: "wrap",
212	};
213	
214	const legendItemStyle: React.CSSProperties = {
215	  display: "inline-flex",
216	  gap: "6px",
217	  alignItems: "center",
218	  fontSize: "0.8rem",
219	  color: "var(--color-text-muted)",
220	};
221	
222	const legendDotStyle: React.CSSProperties = {
223	  width: 10,
224	  height: 10,
225	  borderRadius: "50%",
226	};
